  ('social-worker-moex-01347', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於社會個案工作意義的敘述，下列何者錯誤？', '["社會個案工作是一種有計畫的助人程序，能協助個案去除由心理和精神障礙所引起的功能失調", "社會個案工作透過直接面對面的關係，來協助個人解決其遭遇到的心理暨社會問題", "社會個案工作過程中，為了協助個案解決問題，有時會使用自由聯想技術", "社會個案工作主要為有困擾的個案提供診斷與藥物治療"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
